// Import the necessary modules from the Cloudflare Workers SDK
const { get, post } = require('@cloudflare/workers-toolkit');
const fetch = require('node-fetch');

// Set up API authentication with SendGrid and Stripe
const sendgridApiKey = 'YOUR_SENDGRID_API_KEY';
const stripeApiKey = 'YOUR_STRIPE_API_KEY';

// Define the worker function that will handle requests to the worker
async function handleRequest(request) {
  // Get the request method and URL
  const { method, url } = request;

  // Handle GET requests for email sending
  if (method === 'GET' && url.startsWith('/email/send')) {
    // Authenticate with SendGrid using the API key
    const sendgridAuth = `Bearer ${sendgridApiKey}`;

    // Construct the request to SendGrid's API
    const sendgridRequest = new Request(`https://api.sendgrid.com/v3/mail/send`, {
      method: 'POST',
      headers: {
        Authorization: sendgridAuth,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        personalizations: [
          {
            to: [{ email: 'recipient@example.com' }],
          },
        ],
        from: { email: 'sender@example.com' },
        subject: 'Hello from Cloudflare Workers!',
        content: [
          {
            type: 'text/plain',
            value: 'This is a test email sent from Cloudflare Workers using SendGrid.',
          },
        ],
      }),
    });

    // Make the request to SendGrid's API and handle any errors
    try {
      const sendgridResponse = await fetch(sendgridRequest);
      if (!sendgridResponse.ok) {
        throw new Error(`SendGrid error: ${sendgridResponse.statusText}`);
      }
    } catch (error) {
      console.log(`Error sending email through SendGrid: ${error.message}`);
      return new Response('Error', { status: 500 });
    }

    // Return a success response to the client
    return new Response('Email sent successfully!', { status: 200 });
  }

  // Handle POST requests for payment processing
  if (method === 'POST' && url.startsWith('/payment/process')) {
    // Authenticate with Stripe using the API key
    const stripeAuth = `Bearer ${stripeApiKey}`;

    // Construct the request to Stripe's API
    const stripeRequest = new Request(`https://api.stripe.com/v1/charges`, {
      method: 'POST',
      headers: {
        Authorization: stripeAuth,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        amount: 1000, // $10.00
        currency: 'usd',
        source: request.body.source, // The payment token from the client
        description: 'Test charge',
      }),
    });

    // Make the request to Stripe's API and handle any errors
    try {
      const stripeResponse = await fetch(stripeRequest);
      if (!stripeResponse.ok) {
        throw new Error(`Stripe error: ${stripeResponse.statusText}`);
      }
    } catch (error) {
      console.log(`Error processing payment through Stripe: ${error.message}`);
      return new Response('Error', { status: 500 });
    }

    // Return a success response to the client
    return new Response('Payment processed successfully!', { status: 200 });
  }

  // If no matching route is found, return a 404 error
  return new Response('Not Found', { status: 404 });
}

// Export the worker function to be deployed as a Cloudflare Worker
exports.handler = handleRequest;